"""


def solution(arr):
    if len(arr) == 2:
        return True, [1, 1]

    for i in range(len(arr) - 1):
        if arr[i] > arr[i + 1]:
            break
    else:
        return True, [1, 1]

    for j in range(len(arr) - 1, 0, -1):
        if arr[j] < arr[j - 1]:
            break
    else:
        return True, [1, 1]

    for k in range(i, j + 1):
        if arr[k] < arr[k + 1]:
            return False, []

    return True, [i + 1, j + 1]


if __name__ == '__main__':
    n = int(input())
    arr = list(map(int, input().split()))

    result = solution(arr)
    if result[0]:
        print("yes")
        print(*result[1])
